181	// FindByRole returns personas that can fulfill the specified role.
182	func (l *PersonaLoaderImpl) FindByRole(role string) ([]*Persona, error) {
183		if role == "" {
184			return nil, NewPersonaError(ErrorValidation, "role cannot be empty", nil)
185		}
186	
187		allPersonas, err := l.ListPersonas()
188		if err != nil {
189			return nil, err
190		}
191	
192		var matchingPersonas []*Persona
193	
194		for _, persona := range allPersonas {
195			for _, personaRole := range persona.Roles {
196				if personaRole == role {
197					matchingPersonas = append(matchingPersonas, persona)
198					break
199				}
200			}
201		}
202	
203		return matchingPersonas, nil
204	}
205	
206	// FindByTags returns personas that have all the specified tags.
207	func (l *PersonaLoaderImpl) FindByTags(tags []string) ([]*Persona, error) {
208		if len(tags) == 0 {
209			return nil, NewPersonaError(ErrorValidation, "at least one tag must be specified", nil)
210		}
211	
212		allPersonas, err := l.ListPersonas()
213		if err != nil {
214			return nil, err
215		}
216	
217		var matchingPersonas []*Persona
218	
219		for _, persona := range allPersonas {
220			if hasAllTags(persona.Tags, tags) {
221				matchingPersonas = append(matchingPersonas, persona)
222			}
223		}
224	
225		return matchingPersonas, nil
226	}
