13	// AuditInstalledEntry checks one installed package entry for plugin issues.
14	func AuditInstalledEntry(entry InstalledEntry, fallback *Package) []ValidationIssue {
15		var issues []ValidationIssue
16		root := installedRootPath(entry)
17		if root == "" {
18			issues = append(issues, ValidationIssue{Message: fmt.Sprintf("installed entry %q has no recorded plugin root", entry.Name)})
19			return issues
20		}
21	
22		issues = append(issues, auditRecordedFiles(entry)...)
23	
24		manifest, manifestMissing, manifestIssues := loadPackageDefinitionForAudit(root, fallback)
25		issues = append(issues, manifestIssues...)
26	
27		if manifestMissing {
28			issues = append(issues, ValidationIssue{
29				Path:    filepath.Join(root, "package.yaml"),
30				Message: "missing package.yaml",
31			})
32		}
33	
34		if manifest == nil {
35			manifest = &Package{}
36		}
37	
38		issues = append(issues, ValidatePackageStructure(root, manifest)...)
39		return issues
40	}
41	
42	// ValidatePackageStructure checks the skill, symlink, and executable layout
43	// for a package root before install or after install-state recovery.
44	func ValidatePackageStructure(root string, pkg *Package) []ValidationIssue {
45		if pkg == nil {
46			return []ValidationIssue{{Path: filepath.Join(root, "package.yaml"), Message: "missing package definition"}}
47		}
48		return auditPluginRoot(root, pkg)
49	}
50	
51	func loadPackageDefinitionForAudit(root string, fallback *Package) (*Package, bool, []ValidationIssue) {
52		manifest, manifestMissing, issues, err := LoadPackageManifestWithFallback(root, fallback)
53		if err == nil || os.IsNotExist(err) {
54			// Report validation issues even when package is valid, so audit shows schema problems.
55			return manifest, manifestMissing, issues
56		}
57	
58		// If a partial package was returned (YAML parsed but validation issues exist),
59		// return it with the issues so structural audits can proceed.
60		if manifest != nil {
61			return manifest, false, issues
62		}
63	
64		if len(issues) == 0 {
65			issues = append(issues, ValidationIssue{Path: filepath.Join(root, "package.yaml"), Message: err.Error()})
66		}
67		return manifest, false, issues
68	}
69	
70	func auditPluginRoot(root string, pkg *Package) []ValidationIssue {
71		var issues []ValidationIssue
72	
73		if pkg.APIVersion != "" && pkg.APIVersion != SupportedPackageAPIVersion {
74			issues = append(issues, ValidationIssue{
75				Path:    filepath.Join(root, "package.yaml"),
76				Message: fmt.Sprintf("unsupported `api_version` %q (supported: %s)", pkg.APIVersion, SupportedPackageAPIVersion),
77			})
78		}
79	
80		ignoredBrokenSymlinkPaths := collectIgnoredBrokenSymlinkPaths(root, pkg)
81		for _, symlinkIssue := range auditBrokenSymlinks(root, ignoredBrokenSymlinkPaths) {
82			issues = append(issues, symlinkIssue)
83		}
84	
85		for _, skillRoot := range collectSkillRoots(root, pkg) {
86			issues = append(issues, auditSkillRoot(root, skillRoot)...)
87		}
88	
89		for _, rel := range pkg.Install.Executable {
90			issues = append(issues, auditExecutable(root, rel)...)
91		}
92	
93		return issues
94	}
95	
96	func auditRecordedFiles(entry InstalledEntry) []ValidationIssue {
97		var issues []ValidationIssue
98		seen := map[string]bool{}
99		recordedPaths := append([]string(nil), entry.Files...)
100		if root := installedRootPath(entry); root != "" {
101			recordedPaths = append(recordedPaths, root)
102		}
103		for _, recorded := range recordedPaths {
104			path := ExpandHome(recorded)
105			if path == "" || seen[path] {
106				continue
107			}
108			seen[path] = true
109			info, err := os.Lstat(path)
110			if err != nil {
111				if os.IsNotExist(err) {
112					issues = append(issues, ValidationIssue{Path: path, Message: "missing recorded file or symlink"})
113					continue
114				}
115				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
116				continue
117			}
118			if info.Mode()&os.ModeSymlink == 0 {
119				continue
120			}
121	
122			target, err := os.Readlink(path)
123			if err != nil {
124				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
125				continue
126			}
127			if !filepath.IsAbs(target) {
128				target = filepath.Join(filepath.Dir(path), target)
129			}
130			if _, err := os.Stat(target); err != nil {
131				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
132			}
133		}
134		return issues
135	}
136	
137	func auditBrokenSymlinks(root string, ignored map[string]bool) []ValidationIssue {
138		var issues []ValidationIssue
139		walkRoot := root
140		if resolved, err := filepath.EvalSymlinks(root); err == nil && resolved != "" {
141			walkRoot = resolved
142		}
143	
144		_ = filepath.WalkDir(walkRoot, func(path string, d fs.DirEntry, err error) error {
145			if err != nil {
146				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
147				return nil
148			}
149			if path == walkRoot {
150				return nil
151			}
152	
153			info, err := os.Lstat(path)
154			if err != nil {
155				if os.IsNotExist(err) {
156					issues = append(issues, ValidationIssue{Path: path, Message: "missing installed file"})
157					return nil
158				}
159				issues = append(issues, ValidationIssue{Path: path, Message: err.Error()})
160				return nil
161			}
162			if info.Mode()&os.ModeSymlink == 0 {
163				return nil
164			}
165			if ignored != nil && ignored[path] {
166				return nil
167			}
168	
169			target, err := os.Readlink(path)
170			if err != nil {
171				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink: %v", err)})
172				return nil
173			}
174			if !filepath.IsAbs(target) {
175				target = filepath.Join(filepath.Dir(path), target)
176			}
177			if _, err := os.Stat(target); err != nil {
178				issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("broken symlink target %q: %v", target, err)})
179			}
180			return nil
181		})
182	
183		return issues
184	}
