186	func collectSkillRoots(root string, pkg *Package) []string {
187		seen := map[string]bool{}
188		var roots []string
189	
190		add := func(candidate string) {
191			if strings.TrimSpace(candidate) == "" {
192				return
193			}
194			abs := candidate
195			if resolved, err := filepath.EvalSymlinks(candidate); err == nil && resolved != "" {
196				abs = resolved
197			} else if resolved, err := filepath.Abs(candidate); err == nil && resolved != "" {
198				abs = resolved
199			}
200			if seen[abs] {
201				return
202			}
203			if _, err := os.Stat(candidate); err != nil {
204				return
205			}
206			seen[abs] = true
207			roots = append(roots, candidate)
208		}
209	
210		for _, mapping := range pkg.Install.Skills {
211			sourceRoot := filepath.Join(root, filepath.FromSlash(mapping.Source))
212			add(sourceRoot)
213	
214			cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
215			switch cleanSource {
216			case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
217				add(filepath.Join(root, "skills"))
218			}
219		}
220	
221		return roots
222	}
223	
224	func collectIgnoredBrokenSymlinkPaths(root string, pkg *Package) map[string]bool {
225		ignored := make(map[string]bool)
226		for _, mapping := range pkg.Install.Skills {
227			cleanSource := filepath.Clean(filepath.FromSlash(mapping.Source))
228			switch cleanSource {
229			case filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills"):
230				skillRoot := filepath.Join(root, cleanSource)
231				entries, err := os.ReadDir(skillRoot)
232				if err != nil {
233					continue
234				}
235				for _, entry := range entries {
236					ignored[filepath.Join(skillRoot, entry.Name())] = true
237				}
238			}
239		}
240		return ignored
241	}
242	
243	func auditSkillRoot(packageRoot, root string) []ValidationIssue {
244		var issues []ValidationIssue
245	
246		info, err := os.Stat(root)
247		if err != nil {
248			issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
249			return issues
250		}
251		if !info.IsDir() {
252			issues = append(issues, ValidationIssue{Path: root, Message: "expected a skill directory"})
253			return issues
254		}
255	
256		entries, err := os.ReadDir(root)
257		if err != nil {
258			issues = append(issues, ValidationIssue{Path: root, Message: err.Error()})
259			return issues
260		}
261	
262		for _, entry := range entries {
263			skillPath := filepath.Join(root, entry.Name())
264			skillInfo, err := os.Lstat(skillPath)
265			if err != nil {
266				issues = append(issues, ValidationIssue{Path: skillPath, Message: err.Error()})
267				continue
268			}
269			if skillInfo.Mode()&os.ModeSymlink != 0 {
270				if _, err := os.Stat(skillPath); err != nil {
271					if recovered := recoverSkillDir(packageRoot, root, entry.Name()); recovered != "" {
272						skillPath = recovered
273					} else {
274						issues = append(issues, ValidationIssue{Path: skillPath, Message: fmt.Sprintf("broken symlink: %v", err)})
275						continue
276					}
277				}
278			}
279			if !skillInfo.IsDir() && skillInfo.Mode()&os.ModeSymlink == 0 {
280				continue
281			}
282	
283			skillFile := filepath.Join(skillPath, "SKILL.md")
284			data, err := os.ReadFile(skillFile)
285			if err != nil {
286				if os.IsNotExist(err) {
287					issues = append(issues, ValidationIssue{Path: skillPath, Message: "missing SKILL.md"})
288					continue
289				}
290				issues = append(issues, ValidationIssue{Path: skillFile, Message: err.Error()})
291				continue
292			}
293	
294			for _, issue := range skills.ValidateContent(skillFile, data) {
295				issues = append(issues, ValidationIssue{Path: issue.Path, Message: issue.Message})
296			}
297		}
298	
299		return issues
300	}
301	
302	func recoverSkillDir(packageRoot, skillRoot, skillName string) string {
303		candidate := filepath.Join(packageRoot, "skills", skillName)
304		if info, err := os.Stat(candidate); err == nil && info.IsDir() {
305			return candidate
306		}
307	
308		if strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".agents", "skills")) ||
309			strings.HasSuffix(filepath.Clean(skillRoot), filepath.Join(".claude", "skills")) {
