76	// performUpdate upgrades the DDx binary if a new release is available, then
77	// checks GitHub for the latest version of each installed plugin and updates
78	// any that are outdated (or all if --force). Always refreshes the embedded
79	// `ddx` skill and the AGENTS.md block so projects that ran `ddx init` under
80	// an older DDx version pick up current skill content without re-running init.
81	func performUpdate(workingDir string, opts *UpdateOptions) (*UpdateResult, error) {
82		// Refresh the shipped `ddx` skill copy + AGENTS.md block first, regardless
83		// of whether any plugins are installed. This is what lets older projects
84		// pick up new SKILL.md / reference/*.md content without re-init.
85		refreshShippedSkills(workingDir)
86	
87		state, err := registry.LoadState()
88		if err != nil || len(state.Installed) == 0 {
89			return &UpdateResult{Success: true, Message: "Shipped skills refreshed. No packages installed."}, nil
90		}
91	
92		reg := registry.BuiltinRegistry()
93	
94		var updated []string
95	
96		for _, entry := range state.Installed {
97			// Filter to specific target if requested.
98			if opts.Resource != "" && entry.Name != opts.Resource {
99				continue
100			}
101	
102			pkg, err := reg.Find(entry.Name)
103			if err != nil {
104				continue // not in registry, skip
105			}
106	
107			// Fetch actual latest version from GitHub.
108			latestVersion := pkg.Version
109			if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
110				latestVersion = strings.TrimPrefix(release.TagName, "v")
111			}
112	
113			if !opts.Force && entry.Version == latestVersion {
114				continue
115			}
116	
117			// Install the latest version.
118			installPkg := *pkg
119			installPkg.Version = latestVersion
120			newEntry, err := registry.InstallPackage(&installPkg, workingDir)
121			if err != nil {
122				return nil, fmt.Errorf("updating %s: %w", entry.Name, err)
123			}
124			state.AddOrUpdate(newEntry)
125			updated = append(updated, entry.Name+" "+entry.Version+" → "+latestVersion)
126		}
127	
128		if err := registry.SaveState(state); err != nil {
129			return nil, fmt.Errorf("saving state: %w", err)
130		}
131	
132		if len(updated) == 0 {
133			return &UpdateResult{Success: true, Message: "Shipped skills refreshed. All packages are up to date."}, nil
134		}
135	
136		return &UpdateResult{
137			Success:      true,
138			Message:      "Updated: " + strings.Join(updated, ", "),
139			UpdatedFiles: updated,
140		}, nil
141	}
142	
143	// refreshShippedSkills re-copies the embedded `ddx` skill into the project's
144	// skill directories and refreshes the AGENTS.md DDx block. Safe to call on
145	// every `ddx update` because skills.Install with Force=true handles the
146	// "existing files should be updated" case, and generateAgentsMD's
147	// marker-based merge is idempotent. Stale pre-consolidation skill dirs
148	// (ddx-bead, ddx-run, etc.) are swept by cleanupBootstrapSkills.
149	func refreshShippedSkills(workingDir string) {
150		bootstrapSkillNames := []string{"ddx"}
151		for _, dir := range []string{
152			filepath.Join(workingDir, ".ddx", "skills"),
153			filepath.Join(workingDir, ".agents", "skills"),
154			filepath.Join(workingDir, ".claude", "skills"),
155		} {
156			_ = os.MkdirAll(dir, 0755)
157			cleanupBootstrapSkills(dir, bootstrapSkillNames)
158		}
159		if err := skills.Install(skills.SkillFiles, workingDir, skills.Options{Force: true}); err != nil {
160			_, _ = fmt.Fprintf(os.Stderr, "Warning: skill install failed: %v\n", err)
161		}
162		registerBootstrapDDxSkills(workingDir, true)
163		generateAgentsMD(workingDir)
164	}
