284	func detectConflictsInDir(workingDir string) []ConflictInfo {
285		var conflicts []ConflictInfo
286	
287		// Check for conflict markers in .ddx directory
288		ddxPath := ".ddx"
289		if workingDir != "" {
290			ddxPath = filepath.Join(workingDir, ".ddx")
291		}
292	
293		if _, err := os.Stat(ddxPath); os.IsNotExist(err) {
294			return conflicts
295		}
296	
297		// Walk through .ddx directory looking for conflict markers
298		_ = filepath.Walk(ddxPath, func(path string, info os.FileInfo, err error) error {
299			if err != nil || info.IsDir() {
300				return nil
301			}
302	
303			// Skip binary files
304			if isBinaryFileForUpdate(path) {
305				return nil
306			}
307	
308			// Read file and look for conflict markers
309			data, err := os.ReadFile(path)
310			if err != nil {
311				return nil
312			}
313	
314			content := string(data)
315			lines := strings.Split(content, "\n")
316	
317			for i, line := range lines {
318				if strings.Contains(line, "<<<<<<<") ||
319					strings.Contains(line, "=======") ||
320					strings.Contains(line, ">>>>>>>") {
321	
322					// Extract conflict sections
323					conflict := ConflictInfo{
324						FilePath:     path,
325						LineNumber:   i + 1,
326						ConflictType: "merge",
327					}
328	
329					// Try to extract local and their content
330					if strings.Contains(line, "<<<<<<<") {
331						conflict.LocalContent, conflict.TheirContent = extractConflictContentForUpdate(lines, i)
332					}
333	
334					conflicts = append(conflicts, conflict)
335					break // Only report one conflict per file
336				}
337			}
338	
339			return nil
340		})
341	
342		return conflicts
343	}
