345	func handleUpdateAbortInDir(workingDir string) (*UpdateResult, error) {
346		result := &UpdateResult{}
347	
348		// Check for backup directory
349		backupDir := ".ddx.backup"
350		if workingDir != "" {
351			backupDir = filepath.Join(workingDir, ".ddx.backup")
352		}
353	
354		if _, err := os.Stat(backupDir); os.IsNotExist(err) {
355			result.Success = false
356			result.Message = "No backup found. Nothing to restore."
357			return result, nil
358		}
359	
360		// Check if there's an ongoing update state
361		updateStateFile := ".ddx/.update-state"
362		if workingDir != "" {
363			updateStateFile = filepath.Join(workingDir, ".ddx/.update-state")
364		}
365	
366		if _, err := os.Stat(updateStateFile); os.IsNotExist(err) {
367			result.Success = false
368			result.Message = "No active update operation found."
369			return result, nil
370		}
371	
372		// Restore from backup
373		ddxDir := ".ddx"
374		if workingDir != "" {
375			ddxDir = filepath.Join(workingDir, ".ddx")
376		}
