476	// copyDirForRestore copies a directory recursively for backup/restore operations
477	func copyDirForRestore(src, dst string) error {
478		return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
479			if err != nil {
480				return err
481			}
482	
483			// Calculate destination path
484			relPath, err := filepath.Rel(src, path)
485			if err != nil {
486				return err
487			}
488			dstPath := filepath.Join(dst, relPath)
489	
490			if info.IsDir() {
491				return os.MkdirAll(dstPath, info.Mode())
492			}
493	
494			// Copy file
495			srcFile, err := os.Open(path)
496			if err != nil {
497				return err
498			}
499			defer func() { _ = srcFile.Close() }()
500	
501			dstFile, err := os.Create(dstPath)
502			if err != nil {
503				return err
504			}
505			defer func() { _ = dstFile.Close() }()
506	
507			_, err = io.Copy(dstFile, srcFile)
508			return err
509		})
510	}
