654	func extractConflictContentForUpdate(lines []string, startLine int) (local, their string) {
655		var localLines, theirLines []string
656		var inLocal, inTheir bool
657	
658		for i := startLine; i < len(lines); i++ {
659			line := lines[i]
660	
661			if strings.Contains(line, "<<<<<<<") {
662				inLocal = true
663				continue
664			} else if strings.Contains(line, "=======") {
665				inLocal = false
666				inTheir = true
667				continue
668			} else if strings.Contains(line, ">>>>>>>") {
669				break
670			}
671	
672			if inLocal {
673				localLines = append(localLines, line)
674			} else if inTheir {
675				theirLines = append(theirLines, line)
676			}
677		}
678	
679		return strings.Join(localLines, "\n"), strings.Join(theirLines, "\n")
680	}
