105	// discoverSkills inspects src and returns parallel slices of skill names and
106	// per-skill sub-FSes rooted at the skill content. Handles both bootstrap
107	// (top-level) and plugin (.agents/skills) layouts.
108	func discoverSkills(src fs.FS) ([]string, []fs.FS, error) {
109		if info, err := fs.Stat(src, ".agents/skills"); err == nil && info.IsDir() {
110			entries, err := fs.ReadDir(src, ".agents/skills")
111			if err != nil {
112				return nil, nil, err
113			}
114			var names []string
115			var subs []fs.FS
116			for _, e := range entries {
117				name := e.Name()
118				primary := ".agents/skills/" + name
119				// Try the canonical path first. fs.Stat follows symlinks under os.DirFS,
120				// so a broken symlink yields an error here.
121				if _, statErr := fs.Stat(src, primary); statErr == nil {
122					sub, err := fs.Sub(src, primary)
123					if err != nil {
124						return nil, nil, err
125					}
126					names = append(names, name)
127					subs = append(subs, sub)
128					continue
129				}
130				// Broken symlink (tarball case) — fall back to skills/<name>.
131				fallback := "skills/" + name
132				if _, statErr := fs.Stat(src, fallback); statErr != nil {
133					continue
134				}
135				sub, err := fs.Sub(src, fallback)
136				if err != nil {
137					return nil, nil, err
138				}
139				names = append(names, name)
140				subs = append(subs, sub)
141			}
142			return names, subs, nil
143		}
144	
145		// Default layout: top-level entries are skill directories.
146		entries, err := fs.ReadDir(src, ".")
147		if err != nil {
148			return nil, nil, err
149		}
150		var names []string
151		var subs []fs.FS
152		for _, e := range entries {
153			if !e.IsDir() {
154				continue
155			}
156			sub, err := fs.Sub(src, e.Name())
157			if err != nil {
158				return nil, nil, err
159			}
160			names = append(names, e.Name())
161			subs = append(subs, sub)
162		}
163		return names, subs, nil
164	}
