167	func validateSkillName(name string) error {
168		if name == "" || name == "." || name == ".." {
169			return fmt.Errorf("skills.Install: invalid skill name %q", name)
170		}
171		if strings.ContainsAny(name, `/\`) {
172			return fmt.Errorf("skills.Install: skill name contains path separator: %q", name)
173		}
174		if filepath.IsAbs(name) {
175			return fmt.Errorf("skills.Install: skill name is absolute: %q", name)
176		}
