183	// assertWithinRoot resolves dest (and the existing portion of its path) and
184	// returns an error if it escapes absRoot via symlinks or absolute paths.
185	func assertWithinRoot(dest, absRoot string) error {
186		abs, err := filepath.Abs(dest)
187		if err != nil {
188			return fmt.Errorf("resolve %s: %w", dest, err)
189		}
190		// Walk upward to find an existing ancestor and EvalSymlinks on it; this
191		// catches symlink-escapes even when the leaf does not yet exist.
192		check := abs
193		for {
194			if _, err := os.Lstat(check); err == nil {
195				resolved, err := filepath.EvalSymlinks(check)
196				if err != nil {
197					return fmt.Errorf("resolve symlinks for %s: %w", check, err)
198				}
199				resolvedRoot, rerr := filepath.EvalSymlinks(absRoot)
200				if rerr != nil {
201					// projectRoot may not exist yet — fall back to lexical compare.
202					resolvedRoot = absRoot
203				}
204				if !pathHasPrefix(resolved, resolvedRoot) {
205					return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
