221	func pathHasPrefix(p, prefix string) bool {
222		if p == prefix {
223			return true
224		}
225		sep := string(filepath.Separator)
226		if !strings.HasSuffix(prefix, sep) {
227			prefix += sep
228		}
229		return strings.HasPrefix(p, prefix)
230	}
