97	// resolveBrokenSkillLink attempts to compute a valid absolute path for a
98	// broken project-local skill symlink. It returns an empty string when the
99	// intended target cannot be recovered.
100	//
101	// The symlink target is expected to look like
102	// `.../.ddx/plugins/<plugin>/.agents/skills/<skill>`. We extract <plugin> from
103	// the path segments and look the skill up inside the user's global plugin
104	// directory (`~/.ddx/plugins/<plugin>/.agents/skills/<skill>`), which is the
105	// canonical install location managed by `ddx install`.
106	func resolveBrokenSkillLink(skillName, linkTarget, homeDir string) string {
107		if homeDir == "" {
108			return ""
109		}
110		plugin := pluginFromSkillLinkTarget(linkTarget)
111		if plugin == "" {
112			return ""
113		}
114		return filepath.Join(homeDir, ".ddx", "plugins", plugin, ".agents", "skills", skillName)
115	}
