264	// checkBinaryInstallLocation verifies the running binary is at the canonical install
265	// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
266	// SHA-256 differs from the running binary.
267	func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
268		var issues []DiagnosticIssue
269	
270		homeDir, err := os.UserHomeDir()
271		if err != nil {
272			return issues
273		}
274	
275		canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")
276	
277		// (2) Check whether running binary matches the canonical install location.
278		resolvedExec, _ := filepath.EvalSymlinks(executable)
279		if resolvedExec == "" {
280			resolvedExec = executable
281		}
282		resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
283		execMatchesCanonical := resolvedExec == canonicalPath ||
284			(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
285		if !execMatchesCanonical {
286			issues = append(issues, DiagnosticIssue{
287				Type:        "binary_not_canonical",
288				Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
289				Remediation: []string{
290					"Re-run install.sh to reinstall to the canonical location",
291					fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
292				},
293			})
294		}
295	
296		// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
297		runningSHA, err := computeFileSHA256(executable)
298		if err != nil {
299			return issues
300		}
301	
302		seen := make(map[string]bool)
303		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
304			candidate := filepath.Join(dir, "ddx")
305			if seen[candidate] {
306				continue
307			}
308			seen[candidate] = true
309	
310			info, err := os.Stat(candidate)
311			if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
312				continue
313			}
314	
315			candidateSHA, err := computeFileSHA256(candidate)
316			if err != nil {
317				continue
318			}
319	
320			if candidateSHA == runningSHA {
321				continue // same binary, not stale
322			}
323	
324			issues = append(issues, DiagnosticIssue{
325				Type:        "binary_sha_mismatch",
326				Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
327				Remediation: []string{
328					fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
329					"Or re-run install.sh to update all copies",
330				},
331			})
332		}
333	
334		return issues
335	}
