337	// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
338	func computeFileSHA256(path string) (string, error) {
339		f, err := os.Open(path)
340		if err != nil {
341			return "", err
342		}
343		defer f.Close()
344	
345		h := sha256.New()
346		if _, err := io.Copy(h, f); err != nil {
