func installedRootPath(entry InstalledEntry, projectRoot string) string {
	if len(entry.Files) > 0 {
		return resolveAuditPath(entry.Files[0], projectRoot)
	}
	if strings.TrimSpace(entry.Source) != "" {
		return resolveAuditPath(entry.Source, projectRoot)
	}
	return ""
}

// resolveAuditPath converts a recorded entry path to an absolute path for
// auditing. Absolute paths pass through; relative paths resolve against
// projectRoot. Pre-migration `~/...` paths return empty so the caller can
// treat them as no-ops (FEAT-015 plugin installs are project-local).
func resolveAuditPath(p, projectRoot string) string {
	p = strings.TrimSpace(p)
	if p == "" {
		return ""
	}
	if strings.HasPrefix(p, "~") {
		return ""
	}
	if filepath.IsAbs(p) {
		return p
	}
	if projectRoot == "" {
		return ""
	}
	return filepath.Join(projectRoot, p)
}

