// checkLegacySkillSymlinks reports when project-local skill directories
// contain symlinks (legacy install layout). FEAT-015 installs are real
// files only. Detected symlinks emit a stderr line and recommend
// `ddx update --force`.
func checkLegacySkillSymlinks(workingDir string) []DiagnosticIssue {
	if workingDir == "" {
		return nil
	}
	var issues []DiagnosticIssue
	for _, rel := range []string{filepath.Join(".agents", "skills"), filepath.Join(".claude", "skills")} {
		dir := filepath.Join(workingDir, rel)
		entries, err := os.ReadDir(dir)
		if err != nil {
			continue
		}
		for _, e := range entries {
			p := filepath.Join(dir, e.Name())
			info, err := os.Lstat(p)
			if err != nil {
				continue
			}
			if info.Mode()&os.ModeSymlink == 0 {
				continue
			}
