// TestUninstall_StaleHomeEntriesAreNoOp verifies that an InstalledEntry
// recorded by a pre-FEAT-015 ddx (paths under "~/.ddx/plugins/...") can be
// uninstalled without error even when the legacy targets no longer exist.
// UninstallPackage tolerates os.Remove on missing paths, so the operation
// is a clean no-op.
func TestUninstall_StaleHomeEntriesAreNoOp(t *testing.T) {
	entry := &InstalledEntry{
		Name:    "legacy-plugin",
		Version: "1.0.0",
		Type:    PackageTypePlugin,
		Files: []string{
			"~/.ddx/plugins/legacy-plugin",
			"~/.ddx/plugins/legacy-plugin/skills/legacy-skill",
		},
	}

	if err := UninstallPackage(entry); err != nil {
		t.Fatalf("expected stale home entries to uninstall as no-op, got: %v", err)
	}
}

