// TestUpdate_ForceReplacesStaleSymlinks verifies that `ddx update --force`
// replaces legacy plugin symlinks under `.agents/skills/` (pointing into
// ~/.ddx/plugins/) with real files via skills.Install(Options{Force: true}).
func TestUpdate_ForceReplacesStaleSymlinks(t *testing.T) {
	workDir := t.TempDir()
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)

	for _, rel := range []string{".agents/skills", ".claude/skills"} {
		dir := filepath.Join(workDir, rel)
		require.NoError(t, os.MkdirAll(dir, 0o755))
		legacyTarget := filepath.Join(homeDir, ".ddx", "plugins", "ddx", "skills", "ddx")
		require.NoError(t, os.Symlink(legacyTarget, filepath.Join(dir, "ddx")))
	}

	opts := &UpdateOptions{Force: true}
	if _, err := performUpdate(workDir, opts); err != nil {
		t.Fatalf("performUpdate: %v", err)
	}

	for _, rel := range []string{".agents/skills/ddx", ".claude/skills/ddx"} {
		p := filepath.Join(workDir, rel)
		info, err := os.Lstat(p)
		require.NoError(t, err, "expected real dir at %s", p)
		if info.Mode()&os.ModeSymlink != 0 {
			t.Errorf("legacy symlink not replaced at %s", p)
		}
		if !info.IsDir() {
			t.Errorf("expected directory at %s, got mode %v", p, info.Mode())
		}
		skillFile := filepath.Join(p, "SKILL.md")
		if _, err := os.Stat(skillFile); err != nil {
			t.Errorf("expected SKILL.md at %s: %v", skillFile, err)
		}
	}
}

