)

// TestDoctor_FlagsLegacySymlinks asserts that `ddx doctor` reports an
// error and exits non-zero when project-local skill directories contain
// symlinks left behind by pre-FEAT-015 installs. The recommendation must
// end with `run: ddx update --force`.
func TestDoctor_FlagsLegacySymlinks(t *testing.T) {
	workDir := t.TempDir()
	homeDir := t.TempDir()
	t.Setenv("HOME", homeDir)

	for _, rel := range []string{".agents/skills", ".claude/skills"} {
		dir := filepath.Join(workDir, rel)
		require.NoError(t, os.MkdirAll(dir, 0o755))
		legacyTarget := filepath.Join(homeDir, ".ddx", "plugins", "ddx", "skills", "ddx")
		require.NoError(t, os.Symlink(legacyTarget, filepath.Join(dir, "ddx")))
	}

	factory := NewCommandFactory(workDir)
	output, err := executeWithStdoutCapture(t, factory.NewRootCommand(), "doctor")
	require.Error(t, err, "doctor must exit non-zero when legacy symlinks are present")

	assert.Contains(t, output, "symlink detected under .agents/skills/")
	assert.Contains(t, output, "symlink detected under .claude/skills/")
	assert.Contains(t, output, "run: ddx update --force")
}
